        [MatchConfidenceScore] float NOT NULL,
        [IsMatchResolved] bit NOT NULL,
        [UserId] int NOT NULL,
        [CreatedBy] int NOT NULL,
        [CreatedOn] datetime2 NOT NULL,
        [LastModifiedBy] int NULL,
        [LastModifiedOn] datetime2 NOT NULL,
        [IsDeleted] bit NOT NULL,
        [DeletedOn] datetime2 NULL,
        [DeletedBy] int NULL,
        [IsActive] bit NOT NULL,
        CONSTRAINT [PK_ItemMatches] PRIMARY KEY ([Id]),
        CONSTRAINT [FK_ItemMatches_AspNetUsers_CreatedBy] FOREIGN KEY ([CreatedBy]) REFERENCES [AspNetUsers] ([Id]) ON DELETE NO ACTION,
        CONSTRAINT [FK_ItemMatches_AspNetUsers_DeletedBy] FOREIGN KEY ([DeletedBy]) REFERENCES [AspNetUsers] ([Id]) ON DELETE NO ACTION,
        CONSTRAINT [FK_ItemMatches_AspNetUsers_LastModifiedBy] FOREIGN KEY ([LastModifiedBy]) REFERENCES [AspNetUsers] ([Id]) ON DELETE NO ACTION,
        CONSTRAINT [FK_ItemMatches_AspNetUsers_UserId] FOREIGN KEY ([UserId]) REFERENCES [AspNetUsers] ([Id]) ON DELETE NO ACTION,
        CONSTRAINT [FK_ItemMatches_Items_FoundItemId] FOREIGN KEY ([FoundItemId]) REFERENCES [Items] ([Id]) ON DELETE NO ACTION,
        CONSTRAINT [FK_ItemMatches_Items_LostItemId] FOREIGN KEY ([LostItemId]) REFERENCES [Items] ([Id]) ON DELETE NO ACTION
    );
